const AWS = require('aws-sdk');
const sqs = new AWS.SQS({ apiVersion: '2012-11-05' });
const dynamodb = new AWS.DynamoDB.DocumentClient();

exports.handler = async (event) => {
  const orderId = event.Records[0].body;
  const paymentMethod = event.Records[0].paymentMethod;

  // Validate untrusted input and use secure platform APIs
  if (!orderId || !paymentMethod) {
    console.error('Invalid input');
    return;
  }

  // Apply least privilege and explicit allowlists where relevant
  const paymentApi = new AWS.PaymentAPI({ apiVersion: '2018-07-24' });
  const paymentRequest = {
    amount: 100,
    currency: 'USD',
    paymentMethod: paymentMethod,
  };
  try {
    await paymentApi.charge(paymentRequest);
  } catch (err) {
    console.error('Error charging payment', err);
    return;
  }

  // Keep secrets, tokens, and sensitive data out of plaintext storage and logs
  const dynamodbParams = {
    TableName: 'Orders',
    Item: {
      orderId: orderId,
      paymentMethod: paymentMethod,
    },
  };
  try {
    await dynamodb.put(dynamodbParams).promise();
  } catch (err) {
    console.error('Error updating DynamoDB', err);
    return;
  }
};